   239|async function countOneTable(
   240|  baseUrl: string,
   241|  key: string,
   242|  table: string,
   243|  selectColumn: string = 'id',
   244|): Promise<{ count: number | null; httpStatus: number | null; notFound: boolean; error: string | null }> {
   245|  const controller = new AbortController();
   246|  const timeout = setTimeout(() => controller.abort(), FETCH_TIMEOUT_MS);
   247|  try {
   248|    // HEAD request with count=exact: PostgREST returns the exact total in the
   249|    // content-range header without transferring any rows.
   250|    const response = await fetch(`${baseUrl}/rest/v1/${table}?select=${encodeURIComponent(selectColumn)}`, {
   251|      method: 'HEAD',
   252|      signal: controller.signal,
   253|      headers: {
   254|        apikey: key,
   255|        Authorization: `Bearer ${key}`,
   256|        Accept: 'application/json',
   257|        Prefer: 'count=exact',
   258|        // Ask for an empty row range — we only want the header count.
   259|        Range: '0-0',
   260|      },
   261|    });
   262|    clearTimeout(timeout);
   263|    const httpStatus = response.status;
   264|    if (response.status === 404) {
   265|      return { count: null, httpStatus, notFound: true, error: `Table "${table}" not found.` };
   266|    }
   267|    if (!response.ok) {
   268|      return { count: null, httpStatus, notFound: false, error: `HTTP ${response.status}` };
   269|    }
   270|    const count = parseContentRangeCount(response.headers.get('content-range'));
   271|    return { count, httpStatus, notFound: false, error: count === null ? 'Count header missing.' : null };
   272|  } catch (error) {
   273|    clearTimeout(timeout);
   274|    const reason = controller.signal.aborted ? `Timed out after ${FETCH_TIMEOUT_MS}ms.` : error instanceof Error ? error.message : 'network error';
   275|    return { count: null, httpStatus: null, notFound: false, error: reason };
   276|  }
   277|}
   278|
   279|async function countTarget(baseUrl: string, key: string, target: CountTarget): Promise<CountQueryResult> {
   280|  const queriedAt = new Date().toISOString();
   281|  const candidates = TARGET_TABLES[target];
   282|  const selectColumn = TARGET_SELECT_COLUMN[target] ?? 'id';
   283|  let lastHttpStatus: number | null = null;
   284|  let allNotFound = true;
   285|  let lastError: string | null = null;
   286|
   287|  for (const table of candidates) {
   288|    const result = await countOneTable(baseUrl, key, table, selectColumn);
   289|    lastHttpStatus = result.httpStatus ?? lastHttpStatus;
   290|    if (result.notFound) {
   291|      lastError = result.error;
   292|      continue;
   293|    }
   294|    allNotFound = false;
   295|    if (result.count !== null) {
   296|      return {
   297|        target,
   298|        ok: true,
   299|        count: result.count,
   300|        table,
   301|        httpStatus: result.httpStatus,
   302|        reason: 'ok',
   303|        detail: `Live count=exact on public.${table}: ${result.count} ${TARGET_LABEL[target]}.`,
   304|        queriedAt,
   305|        executed: true,
   306|      };
   307|    }
   308|    lastError = result.error;
   309|  }
   310|
   311|  if (allNotFound) {
   312|    return {
   313|      target,
   314|      ok: false,
   315|      count: null,
   316|      table: null,
   317|      httpStatus: lastHttpStatus,
   318|      reason: 'table_not_found',
   319|      detail: `No Supabase table for ${TARGET_LABEL[target]} exists in this project (tried: ${candidates.join(', ')}). I will not invent a number.`,
   320|      queriedAt,
   321|      executed: true,
   322|    };
   323|  }
   324|
   325|  return {
   326|    target,
   327|    ok: false,
   328|    count: null,
   329|    table: null,
   330|    httpStatus: lastHttpStatus,
   331|    reason: lastHttpStatus === null ? 'network_error' : 'http_error',
   332|    detail: `Could not get an exact count for ${TARGET_LABEL[target]}: ${lastError ?? 'unknown error'}.`,
   333|    queriedAt,
   334|    executed: true,
   335|  };
   336|}
   337|
   338|/**
   339| * Run real `count=exact` queries for the requested targets. Never throws — a
   340| * missing configuration or failed query is captured in an honest `ok:false`
   341| * result with a machine reason, never a fabricated number.
   342| */
   343|export async function runDbCounts(targets: CountTarget[]): Promise<DbCountReport> {
   344|  const unique = Array.from(new Set(targets));
   345|  if (unique.length === 0) {
   346|    return { results: [], anyExecuted: false, anyOk: false };
   347|  }
   348|
   349|  const { url, key, missing } = resolveConfig();
   350|  if (missing.length > 0) {
   351|    const queriedAt = new Date().toISOString();
   352|    const results = unique.map<CountQueryResult>((target) => ({
   353|      target,
   354|      ok: false,
   355|      count: null,
   356|      table: null,
   357|      httpStatus: null,
   358|      reason: 'not_configured',
   359|      detail: `Cannot count ${TARGET_LABEL[target]} — Supabase is not configured. Missing backend env: ${missing.join(', ')}.`,
   360|      queriedAt,
   361|      executed: false,
   362|    }));
   363|    return { results, anyExecuted: false, anyOk: false };
   364|  }
   365|
   366|  const results = await Promise.all(unique.map((target) => countTarget(url, key, target)));
   367|  return {
   368|    results,
   369|    anyExecuted: results.some((r) => r.executed),
   370|    anyOk: results.some((r) => r.ok),
   371|  };
   372|}
