   374|/**
   375| * Render the real count results into an authoritative grounding block injected
   376| * into the chat prompt. The block instructs the model to use ONLY these exact
   377| * numbers and to never narrate "running a query".
   378| *
   379| * Pure function — deterministic.
   380| */
   381|export function buildCountGroundingBlock(report: DbCountReport): string | null {
   382|  if (report.results.length === 0) return null;
   383|
   384|  const lines = report.results.map((result) => {
   385|    if (result.ok && result.count !== null) {
   386|      return `- ${TARGET_LABEL[result.target]}: ${result.count} (exact, from public.${result.table}, count=exact at ${result.queriedAt}).`;
   387|    }
   388|    return `- ${TARGET_LABEL[result.target]}: NO LIVE COUNT — ${result.detail}`;
   389|  });
   390|
   391|  return [
   392|    'LIVE DATABASE COUNTS (already executed by the IVX count tool — these are REAL count=exact results, not a request to run a query):',
   393|    ...lines,
   394|    '',
   395|    'Rules for answering this count question:',
   396|    '- Use ONLY the exact numbers above. Do NOT estimate, round, or invent any count.',
   397|    '- Do NOT write "I will run a query", "I am running these queries now", or "let me query the table" — the query already ran and its results are above.',
   398|    '- For any target marked "NO LIVE COUNT", state the honest reason (not configured / table not found) instead of giving a number.',
